const INIT_STATE = {
    isWebDev: null,
    isSoftDev: null,
    isMLEngineer: null,
    selected: null
};

export default (state=INIT_STATE, action) => {
    switch (action.type) {
        case "WEB_DEV":
            return {...state,isWebDev: true,selected:action.payload};
        case "SOFT_DEV":
            return {...state,isSoftDev: true,selected:action.payload};
        case "ML_ENGINEER":
            return {...state,isMLEngineer:true,selected:action.payload};
        default:
            return state;
    }
}
